// ─── Hooks ────────────────────────────────────────────────────────────────────
function useInView(threshold = 0.15) {
  const ref = useRef(null);
  const [inView, setInView] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) setInView(true); }, { threshold });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);
  return [ref, inView];
}

// ─── FadeIn wrapper ───────────────────────────────────────────────────────────
function FadeIn({ children, delay = 0 }) {
  const ref = useRef(null);
  const [inView, setInView] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) setInView(true); }, { threshold: 0.1 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);
  return (
    <div ref={ref} className={"fade-in" + (inView ? " visible" : "")} style={{ transitionDelay: `${delay}s` }}>
      {children}
    </div>
  );
}

// ─── ProfBar ──────────────────────────────────────────────────────────────────
function ProfBar({ name, level }) {
  const [ref, inView] = useInView(0.3);
  const label = level >= 80 ? "Advanced" : level >= 60 ? "Intermediate" : "Learning";
  return (
    <div ref={ref} className="prof-bar-wrap">
      <div className="prof-bar-meta">
        <span className="prof-bar-name">{name}</span>
        <span className="prof-bar-label">{label}</span>
      </div>
      <div className="prof-bar-track">
        <div className="prof-bar-fill" style={{ width: inView ? `${level}%` : "0%" }} />
      </div>
    </div>
  );
}

// ─── ProjectCard ─────────────────────────────────────────────────────────────
function ProjectCard({ p }) {
  const [open, setOpen] = useState(false);
  return (
    <div className={`project-card${open ? " open" : ""}`} onClick={() => setOpen(o => !o)}>
      <div className="project-card-header">
        <div className="project-num">{p.id}</div>
        <div>
          <div className="project-cat">{p.cat}</div>
          <div className="project-name">{p.name}</div>
          <div className="project-short">{p.short}</div>
        </div>
        <div className="project-meta">
          <span className="project-badge">Android App</span>
          <div className="project-tags">
            {p.tags.map(t => <span key={t} className="project-tag">{t}</span>)}
          </div>
          <span className="project-toggle">
            <span className="arrow">▾</span> Details
          </span>
        </div>
      </div>
      {open && (
        <div className="project-desc" onClick={e => e.stopPropagation()}>
          {p.desc}
          {/* ── APK Download button ─ replace href with real APK link ── */}
          <div style={{ marginTop: "1rem" }}>
            {p.apk ? (
              <a href={p.apk} download className="project-apk-btn">
                ⬇ Download APK
              </a>
            ) : (
              <button
                className="project-apk-btn"
                style={{ opacity: 0.55, cursor: "not-allowed" }}
                title="APK coming soon — add link in PROJECTS array"
                onClick={e => e.preventDefault()}
              >
                ⬇ Download APK (coming soon)
              </button>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

